import React, { useState, useEffect } from 'react';
import { adminService } from '../services/api';
import { LayoutDashboard, Package, ShoppingCart, DollarSign, TrendingUp } from 'lucide-react';

function AdminDashboard() {
  const [stats, setStats] = useState({
    totalProducts: 0,
    totalSales: 0,
    totalRevenue: 0,
    totalCommissionPaid: 0,
    activePartners: 0
  });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    loadDashboard();
  }, []);

  const loadDashboard = async () => {
    try {
      setLoading(true);
      setError('');
      const response = await adminService.getDashboard();
      console.log('📊 Dashboard data:', response.data);
      setStats(response.data);
    } catch (error) {
      console.error('❌ Dashboard error:', error);
      setError('Failed to load dashboard data');
      // Set default stats on error
      setStats({
        totalProducts: 0,
        totalSales: 0,
        totalRevenue: 0,
        totalCommissionPaid: 0,
        activePartners: 0
      });
    } finally {
      setLoading(false);
    }
  };

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      maximumFractionDigits: 0
    }).format(amount);
  };

  if (loading) {
    return (
      <div style={{
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        minHeight: '100vh',
        fontSize: '1.2rem',
        color: '#64748b'
      }}>
        Loading dashboard...
      </div>
    );
  }

  return (
    <div style={{
      padding: '2rem',
      background: '#f8fafc',
      minHeight: '100vh'
    }}>
      {/* Header */}
      <div style={{ marginBottom: '2rem' }}>
        <h1 style={{
          fontSize: '2rem',
          fontWeight: '700',
          color: '#1e293b',
          marginBottom: '0.5rem',
          display: 'flex',
          alignItems: 'center',
          gap: '0.75rem'
        }}>
          <LayoutDashboard size={32} />
          Admin Dashboard
        </h1>
        <p style={{ color: '#64748b', fontSize: '1rem' }}>
          Welcome back! Here's an overview of your business
        </p>
      </div>

      {error && (
        <div style={{
          background: '#fef2f2',
          border: '1px solid #fecaca',
          borderRadius: '12px',
          padding: '1rem',
          marginBottom: '2rem',
          color: '#dc2626'
        }}>
          {error}
        </div>
      )}

      {/* Stats Grid */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
        gap: '1.5rem',
        marginBottom: '2rem'
      }}>
        {/* Total Products */}
        <div style={{
          background: 'linear-gradient(135deg, #3b82f6 0%, #2563eb 100%)',
          borderRadius: '16px',
          padding: '1.5rem',
          color: 'white',
          boxShadow: '0 4px 12px rgba(59, 130, 246, 0.3)',
          transition: 'transform 0.2s ease'
        }}
        onMouseEnter={(e) => e.currentTarget.style.transform = 'translateY(-4px)'}
        onMouseLeave={(e) => e.currentTarget.style.transform = 'translateY(0)'}
        >
          <div style={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'flex-start',
            marginBottom: '1rem'
          }}>
            <div>
              <p style={{
                fontSize: '0.875rem',
                opacity: 0.9,
                marginBottom: '0.5rem',
                fontWeight: '500'
              }}>
                Total Products
              </p>
              <p style={{
                fontSize: '2rem',
                fontWeight: '700',
                lineHeight: 1
              }}>
                {stats.totalProducts || 0}
              </p>
            </div>
            <div style={{
              background: 'rgba(255,255,255,0.2)',
              borderRadius: '12px',
              padding: '0.75rem',
              backdropFilter: 'blur(10px)'
            }}>
              <Package size={24} />
            </div>
          </div>
        </div>

        {/* Total Sales */}
        <div style={{
          background: 'linear-gradient(135deg, #10b981 0%, #059669 100%)',
          borderRadius: '16px',
          padding: '1.5rem',
          color: 'white',
          boxShadow: '0 4px 12px rgba(16, 185, 129, 0.3)',
          transition: 'transform 0.2s ease'
        }}
        onMouseEnter={(e) => e.currentTarget.style.transform = 'translateY(-4px)'}
        onMouseLeave={(e) => e.currentTarget.style.transform = 'translateY(0)'}
        >
          <div style={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'flex-start',
            marginBottom: '1rem'
          }}>
            <div>
              <p style={{
                fontSize: '0.875rem',
                opacity: 0.9,
                marginBottom: '0.5rem',
                fontWeight: '500'
              }}>
                Total Sales
              </p>
              <p style={{
                fontSize: '2rem',
                fontWeight: '700',
                lineHeight: 1
              }}>
                {stats.totalSales || 0}
              </p>
            </div>
            <div style={{
              background: 'rgba(255,255,255,0.2)',
              borderRadius: '12px',
              padding: '0.75rem',
              backdropFilter: 'blur(10px)'
            }}>
              <ShoppingCart size={24} />
            </div>
          </div>
        </div>

        {/* Total Revenue */}
        <div style={{
          background: 'linear-gradient(135deg, #f59e0b 0%, #d97706 100%)',
          borderRadius: '16px',
          padding: '1.5rem',
          color: 'white',
          boxShadow: '0 4px 12px rgba(245, 158, 11, 0.3)',
          transition: 'transform 0.2s ease'
        }}
        onMouseEnter={(e) => e.currentTarget.style.transform = 'translateY(-4px)'}
        onMouseLeave={(e) => e.currentTarget.style.transform = 'translateY(0)'}
        >
          <div style={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'flex-start',
            marginBottom: '1rem'
          }}>
            <div>
              <p style={{
                fontSize: '0.875rem',
                opacity: 0.9,
                marginBottom: '0.5rem',
                fontWeight: '500'
              }}>
                Total Revenue
              </p>
              <p style={{
                fontSize: '1.5rem',
                fontWeight: '700',
                lineHeight: 1
              }}>
                {formatCurrency(stats.totalRevenue || 0)}
              </p>
            </div>
            <div style={{
              background: 'rgba(255,255,255,0.2)',
              borderRadius: '12px',
              padding: '0.75rem',
              backdropFilter: 'blur(10px)'
